Section.HTMLTemplate:
@{
	var main = (List<dynamic>)Model.Data.Main;
	var breadcrumb = (List<dynamic>)Model.Data.BreadCrumb;
	var childrenFolderTreeList = (List<dynamic>)Model.Data.ChildrenFolderTreeList;
	var articleList = (List<dynamic>)Model.Data.ArticleList;
	var createTicketParameters = (List<dynamic>)Model.Data.CreateTicketParameters;

	int? parentFolderTreeID = main?.ToList().FirstOrDefault()?.ParentFolderTreeID is not System.DBNull ? main?.ToList().FirstOrDefault()?.ParentFolderTreeID : 0;
	int? currentFolderTreeID = main?.ToList().FirstOrDefault()?.CurrentFolderTreeID;
	string? segmentTypeID = main?.ToList().FirstOrDefault()?.SegmentTypeID?.Replace("Segment", "");
	int articleListCount = articleList.Count();
}

@functions {


	void RenderBreadCrumb(List<dynamic> breadcrumb)
	{
		<div class="row">
			<div class="col-md-12">
				<div class="d-flex">
					<div class="breadcrumb-lmtl4">
						<a href="javascript:void(0)" data-itsKbc-open-folder-tree-id="" class="breadcrumb-item-lmtl4 py-2-lmtl4"><i class="ph-book-bookmark me-1-lmtl4"></i></a>
						@{
							foreach(var item in breadcrumb){
								<a href="javascript:void(0)" data-itsKbc-open-folder-tree-id="@item.FolderTreeID" class="breadcrumb-item-lmtl4 py-2-lmtl4">@item.Name</a>
							}
						}
					</div>
				</div>
			</div>
		</div>
	}

	void RenderFolderTreeList(List<dynamic> childrenFolderTreeList) {
		string requestUrl = Url.Content("~/Form/Index/ITSMRequest");

		foreach(var item in childrenFolderTreeList) {
			bool hasChildren = 
				(
					item.ITSMKnowledgeBaseCount is not null 
					&& item.ITSMKnowledgeBaseCount > 0 
				) || (
					item.ChildrenFolderTreeCount is not null 
					&& item.ChildrenFolderTreeCount > 0
				);

			<div class="col-xl-3 col-md-4 col-sm-6 d-flex-lmtl4">
				<div class="card-lmtl4 flex-fill-lmtl4">
					@if (hasChildren || true) {
						<a href="javascript:void(0)" data-itsKbc-open-folder-tree-id="@item.FolderTreeID" class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
							<span class="badge-lmtl4 badge-pill-lmtl4 position-absolute-lmtl4 top-0-lmtl4 end-0-lmtl4 m-1-lmtl4 rounded-pill-lmtl4 bg-@item.ColorCssClass">@item.ITSMKnowledgeBaseCount</span>
							<span class="bg-@item.ColorCssClass rounded-pill-lmtl4 p-2-lmtl4 me-3-lmtl4">
								<i class="@item.IconCssClass d-block-lmtl4"></i>
							</span>

							<div class="flex-fill-lmtl4">
								<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@item.Name</h6>
							</div>
						</a>
					} else {
						<a href="@requestUrl" class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
							<span class="badge-lmtl4 badge-pill-lmtl4 position-absolute-lmtl4 top-0-lmtl4 end-0-lmtl4 m-1-lmtl4 rounded-pill-lmtl4 bg-@item.ColorCssClass">@item.ITSMKnowledgeBaseCount</span>
							<span class="bg-@item.ColorCssClass rounded-pill-lmtl4 p-2-lmtl4 me-3-lmtl4">
								<i class="@item.IconCssClass d-block-lmtl4"></i>
							</span>

							<div class="flex-fill-lmtl4">
								<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@item.Name</h6>
							</div>
						</a>
					}
				</div>
			</div>

		}
	}

	void RenderCreateTicket(string formIdent, List<dynamic> createTicketParameters) {
		string requestUrl = Url.Content($"~/Form/Index/{formIdent}");
		var requestParameters = createTicketParameters?
			.Where(item => item?.ControlIdent is not null && item?.Value is not null)
			.Select(item => $"{item.ControlIdent.ToString()}={item.Value.ToString()}")
			.ToList();

		if(requestParameters is not null && requestParameters.Count > 0) {
			requestUrl += "?" + string.Join("&&", requestParameters);
		}

		<div class="col-xl-3 col-md-4 col-sm-6 d-flex-lmtl4">
			<div class="card-lmtl4 flex-fill-lmtl4">

					<a href="@requestUrl" class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
						<span class="me-3-lmtl4">
							<!-- <i class="ph-plus-circle d-block-lmtl4"></i> -->
							<i class="ph-plus-circle text-primary-400 ph-2x d-block-lmtl4"></i>
						</span>

						<div class="flex-fill-lmtl4">
							<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">[#CreateTicket_ITSM#]</h6>
						</div>
					</a>

			</div>
		</div>
	}

	void RenderArticleList(List<dynamic> articleList)
	{
		if(articleList is not null && articleList.Count() > 0) {
			foreach(var item in articleList){
				<div class="col-xl-3 col-md-4 col-sm-6 d-flex-lmtl4">
					<div class="card-lmtl4 flex-fill-lmtl4">
						<a href="javascript:void(0)" data-itsKbc-open-article-id="@item.ID" class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
							<span class="me-3-lmtl4">
								<i class="@item.IconCssClass text-@item.ColorCssClass ph-2x d-block-lmtl4"></i>
							</span>

							<div class="flex-fill-lmtl4">
								<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@item.Title</h6>
								@item.CreateDate @item.AccountID
							</div>
						</a>
					</div>
				</div>
			}
		} else {
			<div class="col-xl-3 col-md-4 col-sm-6 d-flex-lmtl4">
				<div class="card-lmtl4 flex-fill-lmtl4">
					<div class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
						<span class="me-3-lmtl4">
							<i class="ph-file-dotted text-grey ph-2x d-block-lmtl4"></i>
						</span>

						<div class="flex-fill-lmtl4">
							<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@Resx["NoKnowledgeBaseHere_ITSM"]</h6>
						</div>
					</div>
				</div>
			</div>

		}
	}

}

@if(currentFolderTreeID is not null) {
	@{
		RenderBreadCrumb(breadcrumb.ToList());
	}
}

@if(childrenFolderTreeList is not null && childrenFolderTreeList.Count > 0) {

	<div class="row mb-2">
		<div class="col-md-12">
			<ul class="nav-lmtl4 nav-tabs-lmtl4 nav-tabs-underline-lmtl4 d-flex-lmtl4 align-items-baseline-lmtl4">
				<li class="nav-item-lmtl4">
					<span class="nav-link-lmtl4 active-lmtl4">
						<i class="ph-folder me-2-lmtl4"></i> @Resx["Folders_ITSM"]
					</span>
				</li>
				@if(parentFolderTreeID is not null && parentFolderTreeID != 0) {
					<li class="nav-item-lmtl4 ms-auto-lmtl4">
						<a href="javascript:void(0)" data-itsKbc-open-folder-tree-id="@parentFolderTreeID" class="btn-lmtl4 d-block-lmtl4 px-4-lmtl4 py-1-lmtl4 btn-primary-lmtl4"><i class="ph-arrow-elbow-left-up d-block-lmtl4"></i></a>
					</li>
				} else if (parentFolderTreeID is not null) {
					<li class="nav-item-lmtl4 ms-auto-lmtl4">
						<a href="javascript:void(0)" data-itsKbc-open-folder-tree-id="" class="btn-lmtl4 d-block-lmtl4 px-4-lmtl4 py-1-lmtl4 btn-primary-lmtl4"><i class="ph-arrow-elbow-left-up d-block-lmtl4"></i></a>
					</li>
				}
			</ul>
		</div>
	</div>

	<div class="row">
		@{
			RenderFolderTreeList(childrenFolderTreeList.ToList()); 
		}
	</div>

}

@if((childrenFolderTreeList is null || childrenFolderTreeList.Count <= 0) && currentFolderTreeID is not null) {
	<div class="row mb-2">
		<div class="col-md-12">
			<ul class="nav-lmtl4 nav-tabs-lmtl4 nav-tabs-underline-lmtl4 d-flex-lmtl4 align-items-baseline-lmtl4">
				<li class="nav-item-lmtl4">
					<span class="nav-link-lmtl4 active-lmtl4">
						<i class="ph-file me-2-lmtl4"></i> @Resx["CreateTicket_ITSM"]
					</span>
				</li>
				@if(parentFolderTreeID is not null && parentFolderTreeID != 0) {
					<li class="nav-item-lmtl4 ms-auto-lmtl4">
						<a href="javascript:void(0)" data-itsKbc-open-folder-tree-id="@parentFolderTreeID" class="btn-lmtl4 d-block-lmtl4 px-4-lmtl4 py-1-lmtl4 btn-primary-lmtl4"><i class="ph-arrow-elbow-left-up d-block-lmtl4"></i></a>
					</li>
				}
			</ul>
		</div>
	</div>

	<div class="row">
		@{
			RenderCreateTicket(segmentTypeID, createTicketParameters.ToList()); 
		}
	</div>
} else if((childrenFolderTreeList is null || childrenFolderTreeList.Count <= 0) && currentFolderTreeID is not null) {

	<div class="row">
		<div class="col-md-12">
			<div class="alert alert-lmtl4 alert-warning-lmtl4 alert-dismissible-lmtl4 fade show">
				<i class="ph-warning-circle me-2-lmtl4"></i>
				<span class="fw-semibold-lmtl4">Upozornění:</span> V tuto chvíli nemáte dostupné žádné služby. Obraťte se prosím na podporu e-mailem: <a href="mailto:support@@mze.cz" class="alert-link-lmtl4">support@@mze.cz</a>.
				<button type="button" class="btn-close-lmtl4" data-bs-dismiss="alert"></button>
			</div>
		</div>
	</div>

}

@if((childrenFolderTreeList is null || childrenFolderTreeList.Count <= 0) && articleList is not null && articleList.Count() > 0) {
	<div class="row mb-2">
		<div class="col-md-12">
			<ul class="nav-lmtl4 nav-tabs-lmtl4 nav-tabs-underline-lmtl4 d-flex-lmtl4 align-items-baseline-lmtl4">
				<li class="nav-item-lmtl4">
					<span class="nav-link-lmtl4 active-lmtl4">
						<i class="ph-file me-2-lmtl4"></i> @Resx["Articles_ITSM"] <span class="badge badge-pill bg-primary-lmtl4 ms-2-lmtl4">@articleListCount</span>
					</span>
				</li>
			</ul>
		</div>
	</div>

	<div class="row">
		@{
			RenderArticleList(articleList.ToList()); 
		}
	</div>
}

@{
	var itsmKnowledgeBase = (List<dynamic>)Model.Data.ITSMKnowledgeBase;

	int itsmKnowledgeBaseCount = itsmKnowledgeBase.Count();
}

@functions {

	void RenderITSMKnowledgeBase(List<dynamic> itsmKnowledgeBase)
	{
		if(itsmKnowledgeBase is not null && itsmKnowledgeBase.Count() > 0) {
			foreach(var item in itsmKnowledgeBase){								
				<div class="col-xl-3 col-md-4 col-sm-6 d-flex-lmtl4">
					<div class="card-lmtl4 flex-fill-lmtl4">
						<a href="javascript:void(0)" data-itsKbc-open-article-id="@item.ID" class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
							<span class="me-3-lmtl4">
								<i class="@item.IconCssClass text-@item.ColorCssClass ph-2x d-block-lmtl4"></i>
							</span>

							<div class="flex-fill-lmtl4">
								<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@item.Title</h6>
								@item.CreateDate @item.AccountID
							</div>
						</a>
					</div>
				</div>
			}
		} else {
			<div class="col-xl-3 col-md-4 col-sm-6 d-flex-lmtl4">
				<div class="card-lmtl4 flex-fill-lmtl4">
					<div class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
						<span class="me-3-lmtl4">
							<i class="ph-file-dotted text-grey ph-2x d-block-lmtl4"></i>
						</span>

						<div class="flex-fill-lmtl4">
							<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@Resx["NoKnowledgeBaseHere_ITSM"]</h6>
						</div>
					</div>
				</div>
			</div>

		}
	}

}

<div class="row mb-2">
	<div class="col-md-12">
		<ul class="nav-lmtl4 nav-tabs-lmtl4 nav-tabs-underline-lmtl4 custom-underlineDanger">
			<li class="nav-item-lmtl4">
				<span class="nav-link-lmtl4 active-lmtl4">
					<i class="ph-file me-2-lmtl4"></i> @Resx["Articles_ITSM"] <span class="badge badge-pill bg-primary-lmtl4 ms-2-lmtl4">@itsmKnowledgeBaseCount</span>
				</span>
			</li>
		</ul>
	</div>
</div>

<div class="row">
	@{
		RenderITSMKnowledgeBase(itsmKnowledgeBase.ToList()); 
	}
</div>

@{
	var itsmKnowledgeBase = (List<dynamic>)Model.Data.ITSMKnowledgeBase;

	int itsmKnowledgeBaseCount = itsmKnowledgeBase.Count();
}

@if(itsmKnowledgeBaseCount > 0) {
	<span class="badge badge-pill bg-primary-lmtl4 ms-2-lmtl4">@itsmKnowledgeBaseCount</span>
} else {
	<span class="badge badge-pill bg-grey-300 ms-2-lmtl4">0</span>
}

@{
	var mainData = Model.Data.Main[0];
}

<div class="row">
	<div class="col-md-12">
		<div class="card">
			<div class="card-header">

				<div class="d-flex flex-wrap">
					<h4 class="font-weight-semibold mb-1" style="flex: 1 1 auto">@mainData.Title</h4>
					@if(Model.Data.LanguageControlData is not null && Model.Data.LanguageControlData.Count > 1) {
						<div id="ShowInLanguageID" class="js-radiobuttonlist" data-dependence="" data-isinitjsdependency="1" data-cleardepedencitype="Append" data-cssclassinline="d-inline mr-3">
							@foreach(var option in Model.Data.LanguageControlData) {
								@if(option.Selected == 1) {
									<div class="form-check js-radiobuttonlist-item d-inline mr-3">
										<label class="form-check-label">
											<input type="radio" name="ShowInLanguageID" class="form-check-input-styled" data-controltype="RadioButtonListControl" value="@option.Value" data-fouc="" checked="checked" />@option.Title
										</label>
									</div>
								} else {
									<div class="form-check js-radiobuttonlist-item d-inline mr-3">
										<label class="form-check-label">
											<input type="radio" name="ShowInLanguageID" class="form-check-input-styled" data-controltype="RadioButtonListControl" value="@option.Value" data-fouc="" />@option.Title
										</label>
									</div>
								}
							}
							<input type="radio" class="hide js-radiobuttonlist-empty" name="ShowInLanguageID" value="">
						</div>
					}
				</div>
				<ul class="list-inline list-inline-dotted text-muted mb-3">
					<li class="list-inline-item">[#PublishedOn_ITSM#]
						<b>@mainData.CreateDate</b>
					</li>
					<li class="list-inline-item">[#PublishedBy#]
						<b>@mainData.AccountID</b>
					</li>
					<li class="list-inline-item">[#UpdatedOn_ITSM#]
						<b>@mainData.UpdateDate</b>
					</li>
					<li class="list-inline-item">[#UpdatedBy_ITSM#]
						<b>@mainData.LastUpdateAccountID</b>
					</li>
					<li class="list-inline-item">[#ITSMLabelIDs_ITSM#]
						<b>@mainData.ITSMLabelIDs</b>
					</li>
				</ul>

			</div>
			<div class="card-body">
				<div class="row">
					@if (Model.Data.Attachments.Count > 0) {
						<div class="col-md-8">
							@mainData.Content
						</div>
						<div class="col-md-4">
							@foreach (var attachment in Model.Data.Attachments) {
								<div class="col-12-lmtl4 col-lg-12-lmtl4">
									<div class="bg-light-lmtl4 rounded-lmtl4 p-2-lmtl4 my-2-lmtl4">
										<div class="d-flex-lmtl4 align-items-center-lmtl4">
											<div class="me-2-lmtl4">
												<i class="@attachment.IconCssClass ph-2x text-primary-lmtl4" style="color: @attachment.IconColor !important;"></i>
											</div>
											<div class="flex-fill-lmtl4" style="color: #333;">
												<div class="fw-semibold-lmtl4 word-break-word">@attachment.Name</div>
												<div class="fs-sm-lmtl4 text-muted-lmtl4">@attachment.Size MB</div>
											</div>
											<div class="ms-2-lmtl4">
												@if(attachment.FileType=="Image") {
													<a href="~/FileControl/File?id=@attachment.ID&formIdent=@attachment.FormIdent&tableID=@attachment.TableID&Name=@attachment.Name" type="button" data-caption="@attachment.Name" data-fancybox="gallery2" data-thumb="~/FileControl/File?id=@attachment.ID&formIdent=@attachment.FormIdent&tableID=@attachment.TableID&Name=@attachment.Name&isResize=True&width=120&height=42&percent=0&resizeType=Max" rel="group" class="btn-lmtl4 btn-flat-dark-lmtl4 text-body-lmtl4 btn-icon-lmtl4 btn-sm-lmtl4 border-transparent-lmtl4 rounded-pill-lmtl4">
														<i class="ph-eye link-black-lmtl4"></i>
													</a>
												} else if(attachment.FileType=="Pdf"){
													<a href="~/PDF?id=@attachment.ID&formIdent=@attachment.FormIdent&tableID=@attachment.TableID" target="_blank" type="button" class="btn-lmtl4 btn-flat-dark-lmtl4 text-body-lmtl4 btn-icon-lmtl4 btn-sm-lmtl4 border-transparent-lmtl4 rounded-pill-lmtl4">
														<i class="ph-eye link-black-lmtl4"></i>
													</a>
												}
												<a href="~/FileControl/File?id=@attachment.ID&formIdent=@attachment.FormIdent&tableID=@attachment.TableID&Name=@attachment.Name" type="button" class="btn-lmtl4 btn-flat-dark-lmtl4 text-body-lmtl4 btn-icon-lmtl4 btn-sm-lmtl4 border-transparent-lmtl4 rounded-pill-lmtl4">
													<i class="ph-arrow-down link-black-lmtl4"></i>
												</a>
											</div>
										</div>
									</div>
								</div>
							}
						</div>
					} else {
						<div class="col-md-12">
							@mainData.Content
						</div>
					}
				</div>
			</div>

		</div>
	</div>
</div>

@{
	var itsmKnowledgeBase = (List<dynamic>)Model.Data.ITSMKnowledgeBase;

	int itsmKnowledgeBaseCount = itsmKnowledgeBase.Count();
}

@if(itsmKnowledgeBaseCount > 0) {
	<div class="alert alert-lmtl4 alert-info-lmtl4 alert-dismissible-lmtl4 fade show">
		<i class="ph-info me-2-lmtl4"></i>
		<span class="fw-semibold-lmtl4">Doporučení:</span> Pro vybranou kategorii jsou ve znalostní bázi dostupné související články a návody. Před odesláním nového požadavku doporučujeme nejdříve zkontrolovat aktuální znalostní bázi, kde můžete najít rychlé řešení nebo potřebný postup.
		<button type="button" class="btn-close-lmtl4" data-bs-dismiss="alert"></button>
	</div>
}

DataSource.SQL:
DECLARE @UserText NVARCHAR(MAX) = CONCAT(@Subject, N' ' + LEFT(@Description, 400));

IF(ISNULL(@UserText, '') != '') 
	EXEC usr.ITSM_KnowledgeBaseSuggest
		@UserLanguageID     = @UserLanguageID,  -- cs
		@FolderTreeIdent    = @FolderTreeIdent,
		@UserText           = @UserText,
		@Top                = 10,
		@PreferCatalog      = 1,   -- zvýhodni články z dané služby
		@IncludeCatalogOnly = 0,
		@MinFtsRank         = 1,
		@UICultureCode      = @UICultureCode;

Section.HTMLTemplate:
@{
	var itsmKnowledgeBase = (List<dynamic>)Model.Data.ITSMKnowledgeBase;

	int itsmKnowledgeBaseCount = itsmKnowledgeBase.Count();
}

@functions {

	void RenderITSMKnowledgeBase(List<dynamic> itsmKnowledgeBase)
	{
		if(itsmKnowledgeBase is not null && itsmKnowledgeBase.Count() > 0) {
			foreach(var item in itsmKnowledgeBase){								
				<div class="col-xl-6 col-md-12 col-sm-12 d-flex-lmtl4">
					<div class="card-lmtl4 flex-fill-lmtl4">
						<a href="javascript:void(0)" data-itsKbc-open-article-id="@item.ID" class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
							<span class="me-3-lmtl4">
								<i class="@item.IconCssClass text-@item.ColorCssClass ph-2x d-block-lmtl4"></i>
							</span>

							<div class="flex-fill-lmtl4">
								<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@item.Title</h6>
								@item.CreateDate @item.AccountID
							</div>
						</a>
					</div>
				</div>
			}
		}
	}

}

<div class="row">
	@{
		RenderITSMKnowledgeBase(itsmKnowledgeBase.ToList()); 
	}
</div>
